contracts/ComplianceModule.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import {AccessControl} from "@openzeppelin/contracts/access/AccessControl.sol";
import {IdentityRegistry} from "./IdentityRegistry.sol";
import {ComplianceOracle} from "./ComplianceOracle.sol";

/// @title ComplianceModule
/// @notice Enforces HK SFC tokenisation rules: investor eligibility + asset compliance score.
contract ComplianceModule is AccessControl {
    bytes32 public constant POLICY_ADMIN_ROLE = keccak256("POLICY_ADMIN_ROLE");

    IdentityRegistry public immutable identityRegistry;
    ComplianceOracle public immutable complianceOracle;

    uint8 public minComplianceScore;

    event MinScoreUpdated(uint8 newScore);

    constructor(
        address          admin,
        IdentityRegistry registry,
        ComplianceOracle oracle,
        uint8            minScore
    ) {
        _grantRole(DEFAULT_ADMIN_ROLE, admin);
        _grantRole(POLICY_ADMIN_ROLE, admin);
        identityRegistry   = registry;
        complianceOracle   = oracle;
        minComplianceScore = minScore;
    }

    function setMinComplianceScore(uint8 score) external onlyRole(POLICY_ADMIN_ROLE) {
        require(score <= 100, "invalid");
        minComplianceScore = score;
        emit MinScoreUpdated(score);
    }

    /// @notice Gate for minting: investor KYC eligible AND asset AI score >= threshold
    function canMint(address to, bytes32 assetId) external view returns (bool) {
        return identityRegistry.isEligible(to)
            && complianceOracle.isCompliant(assetId, minComplianceScore);
    }

    /// @notice Gate for transfers: both parties must be KYC-eligible (SFC professional investor rule)
    function canTransfer(address from, address to) external view returns (bool) {
        return identityRegistry.isEligible(from) && identityRegistry.isEligible(to);
    }
}

contracts/ComplianceOracle.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import {AccessControl} from "@openzeppelin/contracts/access/AccessControl.sol";

/// @title ComplianceOracle
/// @notice Stores AI-generated compliance scores on-chain, gating RWA token issuance.
///         This satisfies the hackathon requirement: "AI-powered function callable on-chain".
contract ComplianceOracle is AccessControl {
    bytes32 public constant ORACLE_UPDATER_ROLE = keccak256("ORACLE_UPDATER_ROLE");

    struct ScoreRecord {
        uint8  score;       // 0-100
        uint64 updatedAt;   // block.timestamp
        bytes32 reportHash; // keccak256 of full AI report JSON stored off-chain (EigenDA)
    }

    mapping(bytes32 assetId => ScoreRecord) private _scores;

    event ComplianceScoreUpdated(
        bytes32 indexed assetId,
        uint8           score,
        bytes32         reportHash,
        address indexed updater
    );

    error InvalidScore(uint8 score);

    constructor(address admin, address updater) {
        _grantRole(DEFAULT_ADMIN_ROLE, admin);
        _grantRole(ORACLE_UPDATER_ROLE, updater == address(0) ? admin : updater);
    }

    /// @notice Called by the backend oracle service after AI compliance analysis
    function submitScore(bytes32 assetId, uint8 score, bytes32 reportHash)
        external
        onlyRole(ORACLE_UPDATER_ROLE)
    {
        if (score > 100) revert InvalidScore(score);
        _scores[assetId] = ScoreRecord({
            score:      score,
            updatedAt:  uint64(block.timestamp),
            reportHash: reportHash
        });
        emit ComplianceScoreUpdated(assetId, score, reportHash, msg.sender);
    }

    function getScore(bytes32 assetId)
        external
        view
        returns (uint8 score, uint64 updatedAt, bytes32 reportHash)
    {
        ScoreRecord memory r = _scores[assetId];
        return (r.score, r.updatedAt, r.reportHash);
    }

    function isCompliant(bytes32 assetId, uint8 threshold)
        external
        view
        returns (bool)
    {
        return _scores[assetId].score >= threshold;
    }
}

contracts/HarbourRWAToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import {ERC20} from "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import {ERC20Pausable} from "@openzeppelin/contracts/token/ERC20/extensions/ERC20Pausable.sol";
import {AccessControl} from "@openzeppelin/contracts/access/AccessControl.sol";
import {ComplianceModule} from "./ComplianceModule.sol";

/// @title HarbourRWAToken
/// @notice ERC-20 token representing a tokenised real-world asset on Mantle.
///         All mints and transfers are gated by ComplianceModule (KYC + AI oracle score).
///         Implements the core ERC-3643-inspired pattern: compliance-gated transfers.
contract HarbourRWAToken is ERC20Pausable, AccessControl {
    bytes32 public constant ISSUER_ROLE = keccak256("ISSUER_ROLE");

    ComplianceModule public immutable complianceModule;

    /// @notice Asset type: 0 = REIT, 1 = GreenBond, 2 = TradeReceivable
    enum AssetType { REIT, GreenBond, TradeReceivable }

    struct AssetInfo {
        bool      approved;
        AssetType assetType;
        string    name;
        uint256   maturityDate; // 0 for REITs (perpetual)
        uint256   couponBps;    // annual coupon in bps (e.g. 500 = 5%)
        bytes32   prospectusCommitment; // keccak256 of full doc stored on EigenDA
    }

    mapping(bytes32 assetId => AssetInfo) public assets;

    // Dividend / coupon tracking for REIT / GreenBond
    struct DividendRecord {
        uint256 paymentDate;
        uint256 amountPerToken; // in wei equivalent
        bool    distributed;
    }
    mapping(bytes32 assetId => DividendRecord[]) public dividendSchedules;

    event AssetRegistered(bytes32 indexed assetId, AssetType assetType, string name);
    event TokensMinted(address indexed to, bytes32 indexed assetId, uint256 amount);
    event DividendScheduled(bytes32 indexed assetId, uint256 paymentDate, uint256 amountPerToken);

    error ComplianceCheckFailed();
    error AssetNotApproved(bytes32 assetId);
    error NotDueYet();

    constructor(
        string          memory name_,
        string          memory symbol_,
        address                admin,
        ComplianceModule       module
    ) ERC20(name_, symbol_) {
        _grantRole(DEFAULT_ADMIN_ROLE, admin);
        _grantRole(ISSUER_ROLE, admin);
        complianceModule = module;
    }

    // ── Asset management ──────────────────────────────────────────────────────

    function registerAsset(
        bytes32   assetId,
        AssetType assetType,
        string    calldata assetName,
        uint256   maturityDate,
        uint256   couponBps,
        bytes32   prospectusCommitment
    ) external onlyRole(DEFAULT_ADMIN_ROLE) {
        assets[assetId] = AssetInfo({
            approved:               true,
            assetType:              assetType,
            name:                   assetName,
            maturityDate:           maturityDate,
            couponBps:              couponBps,
            prospectusCommitment:   prospectusCommitment
        });
        emit AssetRegistered(assetId, assetType, assetName);
    }

    function scheduleDividend(
        bytes32 assetId,
        uint256 paymentDate,
        uint256 amountPerToken
    ) external onlyRole(ISSUER_ROLE) {
        dividendSchedules[assetId].push(DividendRecord({
            paymentDate:    paymentDate,
            amountPerToken: amountPerToken,
            distributed:    false
        }));
        emit DividendScheduled(assetId, paymentDate, amountPerToken);
    }

    // ── Minting (compliance gated) ────────────────────────────────────────────

    function mintForAsset(
        address to,
        uint256 amount,
        bytes32 assetId
    ) external whenNotPaused onlyRole(ISSUER_ROLE) {
        if (!assets[assetId].approved) revert AssetNotApproved(assetId);
        if (!complianceModule.canMint(to, assetId)) revert ComplianceCheckFailed();
        _mint(to, amount);
        emit TokensMinted(to, assetId, amount);
    }

    // ── Transfer override (compliance gated) ──────────────────────────────────

    function _update(address from, address to, uint256 value) internal override {
        // Skip compliance check for mint (from == 0) and burn (to == 0)
        if (from != address(0) && to != address(0)) {
            if (!complianceModule.canTransfer(from, to)) revert ComplianceCheckFailed();
        }
        super._update(from, to, value);
    }

    // ── Admin ─────────────────────────────────────────────────────────────────

    function pause()   external onlyRole(DEFAULT_ADMIN_ROLE) { _pause(); }
    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) { _unpause(); }
}

contracts/IdentityRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import {AccessControl} from "@openzeppelin/contracts/access/AccessControl.sol";

/// @title IdentityRegistry
/// @notice On-chain KYC whitelist for RWA token investors (SFC Suitability Requirement).
contract IdentityRegistry is AccessControl {
    bytes32 public constant COMPLIANCE_OFFICER_ROLE = keccak256("COMPLIANCE_OFFICER_ROLE");

    struct Investor {
        bool    isVerified;
        bool    amlClear;
        bytes32 jurisdiction; // e.g. keccak256("HK") or keccak256("SG")
        uint64  kycExpiry;    // unix timestamp
    }

    mapping(address investor => Investor) private _investors;

    event InvestorUpdated(
        address indexed investor,
        bool isVerified,
        bool amlClear,
        bytes32 jurisdiction,
        uint64 kycExpiry
    );

    constructor(address admin) {
        _grantRole(DEFAULT_ADMIN_ROLE, admin);
        _grantRole(COMPLIANCE_OFFICER_ROLE, admin);
    }

    function upsertInvestor(
        address investor,
        bool    isVerified,
        bool    amlClear,
        bytes32 jurisdiction,
        uint64  kycExpiry
    ) external onlyRole(COMPLIANCE_OFFICER_ROLE) {
        _investors[investor] = Investor({
            isVerified:   isVerified,
            amlClear:     amlClear,
            jurisdiction: jurisdiction,
            kycExpiry:    kycExpiry
        });
        emit InvestorUpdated(investor, isVerified, amlClear, jurisdiction, kycExpiry);
    }

    function getInvestor(address investor) external view returns (Investor memory) {
        return _investors[investor];
    }

    /// @notice Returns true if investor passes KYC + AML + not expired
    function isEligible(address investor) external view returns (bool) {
        Investor memory p = _investors[investor];
        return p.isVerified && p.amlClear && p.kycExpiry >= uint64(block.timestamp);
    }
}

contracts/YieldAggregator.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import {AccessControl} from "@openzeppelin/contracts/access/AccessControl.sol";

/// @title YieldAggregator
/// @notice Routes idle RWA proceeds to USDY (Ondo) and mETH Protocol on Mantle for yield.
///         Uses interface abstraction so it can target real Mantle mainnet contracts.
interface IUSDY {
    function deposit(address recipient, uint256 amount) external returns (uint256 shares);
    function redeem(uint256 shares, address recipient) external returns (uint256 amount);
    function balanceOf(address account) external view returns (uint256);
}

interface ImETH {
    function stake() external payable returns (uint256 shares);
    function unstake(uint256 shares) external returns (uint256 amount);
    function balanceOf(address account) external view returns (uint256);
}

contract YieldAggregator is AccessControl {
    bytes32 public constant MANAGER_ROLE = keccak256("MANAGER_ROLE");

    IUSDY public usdy;
    ImETH public meth;

    mapping(address user => uint256 usdyShares) public usdyDeposits;
    mapping(address user => uint256 methShares)  public methDeposits;

    event DepositedUSDY(address indexed user, uint256 amount, uint256 shares);
    event RedeemedUSDY(address indexed user, uint256 shares, uint256 amount);
    event StakedMETH(address indexed user, uint256 ethAmount, uint256 shares);
    event UnstakedMETH(address indexed user, uint256 shares, uint256 amount);

    constructor(address admin, address usdyAddr, address methAddr) {
        _grantRole(DEFAULT_ADMIN_ROLE, admin);
        _grantRole(MANAGER_ROLE, admin);
        usdy = IUSDY(usdyAddr);
        meth = ImETH(methAddr);
    }

    // ── USDY ──────────────────────────────────────────────────────────────────

    function depositUSDY(address user, uint256 amount) external onlyRole(MANAGER_ROLE) {
        uint256 shares = usdy.deposit(address(this), amount);
        usdyDeposits[user] += shares;
        emit DepositedUSDY(user, amount, shares);
    }

    function redeemUSDY(address user, uint256 shares) external onlyRole(MANAGER_ROLE) returns (uint256) {
        require(usdyDeposits[user] >= shares, "insufficient shares");
        usdyDeposits[user] -= shares;
        uint256 amount = usdy.redeem(shares, user);
        emit RedeemedUSDY(user, shares, amount);
        return amount;
    }

    // ── mETH ──────────────────────────────────────────────────────────────────

    function stakeMETH(address user) external payable onlyRole(MANAGER_ROLE) {
        uint256 shares = meth.stake{value: msg.value}();
        methDeposits[user] += shares;
        emit StakedMETH(user, msg.value, shares);
    }

    function unstakeMETH(address user, uint256 shares) external onlyRole(MANAGER_ROLE) returns (uint256) {
        require(methDeposits[user] >= shares, "insufficient shares");
        methDeposits[user] -= shares;
        uint256 amount = meth.unstake(shares);
        emit UnstakedMETH(user, shares, amount);
        return amount;
    }

    // ── View ──────────────────────────────────────────────────────────────────

    function totalUSDYShares(address user) external view returns (uint256) {
        return usdyDeposits[user];
    }

    function totalMETHShares(address user) external view returns (uint256) {
        return methDeposits[user];
    }

    // Allow receiving ETH for mETH staking
    receive() external payable {}
}

